let _beforeUnloadHandler = null;

export function loadContent(key) {
    return localStorage.getItem(key);
}

export function saveContent(key, content) {
    localStorage.setItem(key, content);
}

export function clearContent(key) {
    localStorage.removeItem(key);
}

export function enableBeforeUnload() {
    if (_beforeUnloadHandler) return;
    _beforeUnloadHandler = (e) => {
        e.preventDefault();
    };
    window.addEventListener("beforeunload", _beforeUnloadHandler);
}

export function disableBeforeUnload() {
    if (!_beforeUnloadHandler) return;
    window.removeEventListener("beforeunload", _beforeUnloadHandler);
    _beforeUnloadHandler = null;
}

@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput" placeholder="Type your notes here..."></textarea>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt.HasValue)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private const string StorageKey = "notepad-content";
    private const int AutoSaveIntervalSeconds = 30;

    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private DateTime? lastSavedAt;

    private bool HasUnsavedChanges => content != savedContent;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        module = await JS.InvokeAsync<IJSObjectReference>(
            "import", Assets["Components/Pages/Notepad.razor.js"]);

        var stored = await module.InvokeAsync<string?>("loadContent", StorageKey);
        if (!string.IsNullOrEmpty(stored))
        {
            content = stored;
            savedContent = stored;
            StateHasChanged();
        }

        autoSaveTimer = new System.Threading.Timer(
            async _ => await InvokeAsync(AutoSave),
            null,
            TimeSpan.FromSeconds(AutoSaveIntervalSeconds),
            TimeSpan.FromSeconds(AutoSaveIntervalSeconds));
    }

    private async Task AutoSave()
    {
        if (!HasUnsavedChanges || module is null) return;
        await Save();
    }

    private async Task SaveNow()
    {
        if (module is null) return;
        await Save();
    }

    private async Task Save()
    {
        await module!.InvokeVoidAsync("saveContent", StorageKey, content);
        savedContent = content;
        lastSavedAt = DateTime.Now;
        await UpdateBeforeUnload();
        StateHasChanged();
    }

    private async Task Clear()
    {
        if (module is null) return;
        content = string.Empty;
        savedContent = string.Empty;
        lastSavedAt = null;
        await module.InvokeVoidAsync("clearContent", StorageKey);
        await UpdateBeforeUnload();
    }

    private async Task UpdateBeforeUnload()
    {
        if (module is null) return;
        if (HasUnsavedChanges)
            await module.InvokeVoidAsync("enableBeforeUnload");
        else
            await module.InvokeVoidAsync("disableBeforeUnload");
    }

    protected override async Task OnAfterRenderAsync(bool firstRender, bool _)
        => await UpdateBeforeUnload();

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
            await autoSaveTimer.DisposeAsync();

        if (module is not null)
        {
            await module.InvokeVoidAsync("disableBeforeUnload");
            await module.DisposeAsync();
        }
    }
}

